  ('islands-e3452428-moex-00047', 'islands-e3452428', 'islands-e3452428-moex-114-4dccc0e6', 'sub-islands-e3452428-02', NULL, 'single_choice', '有關我國一般行政機關與獨立機關之敘述，下列何者錯誤？ 其組織均需以法律規定   均設業務單位與輔助單位 均為行使公權力的組織   獨立機關均為合議制組織', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "06786d62fb55", "answer_pdf_sha1": "242e83f0aff7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0512", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
